// ROLLUP_NO_REPLACE 
 const ipados26 = "{\"parsed\":{\"_path\":\"/fr/_archived/ipados26\",\"_dir\":\"_archived\",\"_draft\":false,\"_partial\":true,\"_locale\":\"\",\"title\":\"iPadOS 26 : L'iPad redevient (enfin) utile\",\"description\":\"Avec l'arrivée des fenêtres flottantes, iPadOS 18 transforme enfin l'iPad en outil productif digne de ce nom. Fini les limitations du Split View : on peut désormais jongler entre plusieurs apps comme sur un ordinateur classique.\",\"image\":\"/images/articles/ipad-mini-6.jpg\",\"createdAt\":\"15-06-2025\",\"id\":16,\"keywords\":\"iPadOS 18, Apple, iPad mini 6, productivité, fenêtres flottantes, Liquid Glass, Apple Intelligence\",\"summary\":\"iPadOS 18 introduit une vraie gestion des fenêtres, rendant l'iPad plus polyvalent. Un changement discret, mais fondamental pour ceux qui attendaient depuis des années un multitâche sérieux sur tablette.\",\"og\":{\"title\":\"iPadOS 26 : L'iPad redevient (enfin) utile\",\"description\":\"Avec l'arrivée des fenêtres flottantes, iPadOS 18 transforme enfin l'iPad en outil productif digne de ce nom. Découvrez comment cette mise à jour change la donne pour le multitâche sur tablette.\",\"image\":\"/images/articles/ipad-mini-6.jpg\",\"url\":\"/fr/ipados26\",\"type\":\"article\",\"site_name\":\"houedanou.com\",\"locale\":\"fr_FR\"},\"twitter\":{\"card\":\"summary_large_image\",\"title\":\"iPadOS 26 : L'iPad redevient (enfin) utile\",\"description\":\"Fenêtres flottantes, multitâche amélioré : iPadOS 18 transforme enfin l'iPad en véritable outil de productivité. Fini les limitations du Split View !\",\"image\":\"/images/articles/ipad-mini-6.jpg\",\"creator\":\"@votre_compte_twitter\"},\"article\":{\"published_time\":\"2025-06-15T00:00:00Z\",\"modified_time\":\"2025-06-15T00:00:00Z\",\"author\":\"Votre Nom\",\"section\":\"Technologie\",\"tag\":[\"iPadOS 18\",\"Apple\",\"iPad mini 6\",\"productivité\",\"fenêtres flottantes\",\"Liquid Glass\",\"Apple Intelligence\"]},\"schema\":{\"type\":\"Article\",\"headline\":\"iPadOS 26 : L'iPad redevient (enfin) utile\",\"description\":\"Avec l'arrivée des fenêtres flottantes, iPadOS 18 transforme enfin l'iPad en outil productif digne de ce nom. Fini les limitations du Split View : on peut désormais jongler entre plusieurs apps comme sur un ordinateur classique.\",\"image\":\"/images/articles/ipad-mini-6.jpg\",\"datePublished\":\"2025-06-15\",\"dateModified\":\"2025-06-15\",\"author\":\"Votre Nom\",\"publisher\":\"Votre Site\"},\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"iPadOS 26 : L'iPad redevient (enfin) utile\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mon iPad Mini prenait la poussière depuis un moment. Il me servait pour deux usages : prendre des notes manuscrites en réunion (avec un stylet Bluetooth Ugreen, suffisant pour éviter l'achat d'un Apple Pencil hors de prix) et regarder quelques séries.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est tout.  J'avais tenté d'en faire une machine de travail d'appoint, mais l'expérience était frustrante. Impossible, par exemple, de suivre une vidéo YouTube tout en prenant des notes sérieusement. Le multitâche façon \\\"Split View\\\" est rigide, limitant, et loin de ce que propose un environnement de bureau classique.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"puis-est-arrivé-ipados-19-ou-pluttôt-26\"},\"children\":[{\"type\":\"text\",\"value\":\"Puis est arrivé iPadOS 19, ou pluttôt 26.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On peut passer sur les effets de transparence de \\\"Liquid Glass\\\" ou sur la promesse d'une IA omniprésente (Apple Intelligence). Le vrai changement, \"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"c'est l'arrivée des fenêtres flottantes\"}]},{\"type\":\"text\",\"value\":\".\\nOui, des vraies fenêtres.\\nRedimensionnables, déplaçables, avec une vraie gestion de l'espace de travail. Pour la première fois, on peut travailler sur plusieurs applications à la fois, sans avoir l'impression de devoir faire des compromis.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Résultat : je peux désormais suivre un cours Udemy d'un côté, tout en retouchant une photo dans Affinity Photo de l'autre, sans avoir à jongler ou à sacrifier la lisibilité.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"img\",\"props\":{\"alt\":\"iPad mini 6\",\"src\":\"/images/articles/ipad-mini-6.jpg\"},\"children\":[]}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"est-ce-que-ça-transforme-lipad-en-ordinateur\"},\"children\":[{\"type\":\"text\",\"value\":\"Est-ce que ça transforme l'iPad en ordinateur ?\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pas tout à fait. Pour du développement web ou de la production vidéo/audio lourde, un MacBook (ou un PC) reste indispensable.\\nMais pour la prise de notes, la bureautique, la retouche légère ou la formation en ligne, l'iPad devient vraiment fonctionnel.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Petit bémol au passage : les effets visuels de Liquid Glass nuisent parfois à la lisibilité des notifications. Rien de bloquant, mais à signaler.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Bref, iPadOS 26 ne révolutionne pas tout, mais il débloque enfin le vrai potentiel de l'iPad. Et ça, c'est déjà un grand pas.\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"puis-est-arrivé-ipados-19-ou-pluttôt-26\",\"depth\":2,\"text\":\"Puis est arrivé iPadOS 19, ou pluttôt 26.\"},{\"id\":\"est-ce-que-ça-transforme-lipad-en-ordinateur\",\"depth\":2,\"text\":\"Est-ce que ça transforme l'iPad en ordinateur ?\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:_archived:ipados26.md\",\"_source\":\"content\",\"_file\":\"fr/_archived/ipados26.md\",\"_stem\":\"fr/_archived/ipados26\",\"_extension\":\"md\"},\"hash\":\"FO1w8f68M8\"}";

